#!/usr/bin/env python3
from pathlib import Path
import argparse, json, html, re, shutil, datetime

ROOT=Path('.')
DATA=Path('data/proof-cards/proof-cards-v19.json')
TOKEN='0xA61a3B3a130a9c20768EEBF97E21515A6046a1fA'

CSS="""
:root{--navy:#06142b;--mid:#102544;--blue:#183a63;--gold:#b98b2f;--gold2:#ead39a;--ivory:#f7f1e7;--ink:#172033;--muted:#5c6980;--line:#e2d2b8;--white:#fff;--green:#1f7a59;--red:#8f2d2d}*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;background:var(--ivory);color:var(--ink);font-family:Inter,ui-sans-serif,system-ui,-apple-system,Segoe UI,Arial,sans-serif;line-height:1.58}.nav{position:sticky;top:0;z-index:50;background:rgba(6,20,43,.985);padding:14px 24px;box-shadow:0 14px 40px rgba(6,20,43,.20)}.nav .inner{max-width:1260px;margin:auto;display:flex;gap:18px;align-items:center;justify-content:space-between}.brand{color:#fff;text-decoration:none;font-weight:950;letter-spacing:-.03em}.links{display:flex;gap:14px;flex-wrap:wrap}.links a{color:#fff;text-decoration:none;font-weight:800;font-size:14px}.hero{background:radial-gradient(circle at 78% 16%,rgba(234,211,154,.25),transparent 28%),linear-gradient(135deg,#06142b 0%,#0b2242 56%,#2a2110 100%);color:white;padding:94px 24px 82px;border-bottom:7px solid var(--gold)}.wrap{max-width:1260px;margin:auto}.kicker{color:var(--gold2);font-weight:950;letter-spacing:.17em;text-transform:uppercase;font-size:12px}.hero h1{font-size:clamp(48px,7vw,96px);line-height:.9;margin:14px 0 18px;letter-spacing:-.06em;max-width:1050px}.lead{font-size:21px;max-width:940px;color:#edf2fb}.buttons{display:flex;gap:12px;flex-wrap:wrap;margin-top:28px}.btn{display:inline-block;padding:12px 17px;border-radius:999px;text-decoration:none;font-weight:950;background:var(--gold);color:#06142b}.btn.secondary{background:#fff;color:#06142b}.section{padding:56px 24px}.section h2{font-size:clamp(34px,4vw,58px);line-height:1;margin:0 0 16px;letter-spacing:-.05em}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:18px}.card{background:white;border:1px solid var(--line);border-radius:26px;padding:24px;box-shadow:0 24px 56px rgba(6,20,43,.07)}.card.hero-card{border:2px solid var(--gold);background:linear-gradient(135deg,#fff,#fff7df)}.card h3{font-size:24px;line-height:1.08;margin:8px 0 10px}.tag{display:inline-block;background:#06142b;color:white;padding:6px 10px;border-radius:999px;font-size:12px;font-weight:950}.tag.gold{background:var(--gold);color:#06142b}.two{display:grid;grid-template-columns:minmax(0,1.1fr) minmax(0,.9fr);gap:18px}.three{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}.table{width:100%;border-collapse:separate;border-spacing:0;border:1px solid var(--line);border-radius:22px;overflow:hidden;background:white}.table th{background:#06142b;color:white;text-align:left;padding:13px;font-size:12px;text-transform:uppercase;letter-spacing:.08em}.table td{padding:14px;border-top:1px solid #ebdfc8;vertical-align:top}.flow{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:10px}.step{background:#06142b;color:white;border-radius:18px;padding:14px;min-height:88px;font-weight:850}.step small{display:block;color:var(--gold2);font-weight:950;margin-bottom:6px}.note{background:#fff8e8;border:1px solid #e5d2a1;border-radius:26px;padding:24px}.mono{background:#06142b;color:#eaf1fb;border-radius:22px;padding:18px;overflow:auto;font-family:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace;font-size:13px}.list{margin:0;padding-left:18px}.list li{margin:7px 0}.bar{height:12px;background:#ebdfc8;border-radius:999px;overflow:hidden;margin:8px 0 16px}.bar span{display:block;height:100%;background:linear-gradient(90deg,var(--gold),#fff0b5)}.pc-head{background:linear-gradient(135deg,#06142b,#102544 62%,#3b2c10);color:white;padding:74px 24px;border-bottom:7px solid var(--gold)}.pc-head h1{font-size:clamp(42px,6.5vw,84px);line-height:.92;margin:14px 0 14px;letter-spacing:-.055em}.pc-head .lead{color:#edf2fb}.badge-row{display:flex;gap:10px;flex-wrap:wrap;margin-top:18px}.badge{background:rgba(255,255,255,.12);border:1px solid rgba(255,255,255,.22);border-radius:999px;padding:8px 11px;color:#fff;font-weight:800;font-size:13px}.subnav{background:#fff;border-bottom:1px solid var(--line);padding:12px 24px}.subnav .wrap{display:flex;gap:12px;flex-wrap:wrap}.subnav a{color:#06142b;text-decoration:none;font-weight:850}.atlas{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:14px}.atlas a{display:block;background:#fff;border:1px solid var(--line);border-radius:18px;padding:15px;text-decoration:none;color:var(--ink);font-weight:850}.atlas a strong{display:block;color:#06142b}.atlas a:hover{border-color:var(--gold);box-shadow:0 20px 45px rgba(6,20,43,.08)}.matrix{display:grid;grid-template-columns:repeat(5,1fr);gap:10px}.matrix .cell{background:#fff;border:1px solid var(--line);border-radius:16px;padding:12px;text-align:center}.big-number{font-size:34px;font-weight:950;color:#06142b}.footer{padding:40px 24px;background:#06142b;color:#dbe5f4}.footer a{color:#fff}@media(max-width:800px){.two,.three{grid-template-columns:1fr}.hero h1,.pc-head h1{font-size:42px}.links{display:none}.matrix{grid-template-columns:repeat(2,1fr)}}
"""

def esc(x): return html.escape(str(x), quote=True)
def load_cards(): return json.loads(DATA.read_text())
def route_text(contracts): return ' -> '.join(contracts[:12]) + (' -> ...' if len(contracts)>12 else '')
def contract_note(x):
    mapping={'AEPGoalOSCommitRegistry':'records the sovereign aim and authorized scope','AEPRunCommitmentRegistry':'records the planned run and agent/tool boundary','JobRegistry':'posts the proof mission','JobClaimBondManager':'holds the builder claim bond','ProofSubmissionRegistry':'anchors the ProofBundle','ReviewerBondRegistry':'holds reviewer or red-team accountability','ProofCardRegistry':'registers the public-safe Proof Card','ProofCredentialRegistry':'issues non-transferable proof credentials','ReputationRegistry':'updates proof-backed reputation','AEPEvidenceDocketRegistry':'anchors the Evidence Docket','AEPSelectionGate':'decides scoped upgrade rights','AEPRollbackRegistry':'records rollback readiness','AEPChronicleRegistry':'preserves institutional memory','AlphaWorkUnitLedger':'measures proof work','AEPRewardVault':'routes verified rewards','TreasuryRouter':'routes reinvestment','CommercializationPerformanceVault':'tracks performance-linked commercialization milestones'}
    return mapping.get(x, 'contributes a specialized proof, governance, settlement, safety, or memory function')

def nav():
    return """<nav class='nav'><div class='inner'><a class='brand' href='index.html'>GoalOS AGIALPHA Ascension</a><div class='links'><a href='proof-cards.html'>Proof Cards</a><a href='proof-card-010.html'>Latest Card</a><a href='agialpha-ledger-route.html'>AGIALPHA</a><a href='sovereign-rsi-control-plane.html'>RSI</a><a href='evidence-docket.html'>Evidence</a></div></div></nav>"""

def page(title, body):
    return "<!doctype html><html lang='en'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>"+esc(title)+"</title><style>"+CSS+"</style></head><body>"+nav()+body+"<footer class='footer'><div class='wrap'><strong>GoalOS AGIALPHA Ascension</strong><p>Experimental proof-card command center. Public pages are illustrative until live Evidence Dockets are completed.</p></div></footer></body></html>"

def card_grid(cards):
    out="<div class='grid'>"
    for c in cards:
        cls='card hero-card' if c['id'] in ['009','010'] else 'card'
        out += f"<article class='{cls}'><span class='tag'>{esc('Proof Card '+c['id'])}</span><h3>{esc(c['title'])}</h3><p><strong>{esc(c['level'])}</strong></p><p>{esc(c['short'])}</p><p><a class='btn' href='proof-card-{esc(c['id'])}.html'>Open stable page</a></p></article>"
    return out+'</div>'

def home_block(cards):
    return f"""<!-- GOALOS_PROOF_ATLAS_V19_START --><section id='proof-card-command-center' class='section'><div class='wrap'><div class='kicker'>Institutional Proof Card Atlas</div><h2>Ten proof cards. One compounding evidence graph.</h2><p class='lead'>GoalOS-native alpha-AGI Ascension turns AI work into auditable institutional capability. AGIALPHA coordinates proof-settled missions, Evidence Dockets make claims inspectable, and RSI reuses only what proved itself.</p><div class='matrix'><div class='cell'><div class='big-number'>10</div><div>stable proof pages</div></div><div class='cell'><div class='big-number'>1</div><div>AGIALPHA ledger route</div></div><div class='cell'><div class='big-number'>AEP</div><div>evidence protocol</div></div><div class='cell'><div class='big-number'>RSI</div><div>upgrade rights</div></div><div class='cell'><div class='big-number'>0</div><div>unproven propagation</div></div></div><br>{card_grid(cards)}<div class='buttons'><a class='btn' href='proof-cards.html'>Open full proof-card gallery</a><a class='btn secondary' href='proof-card-010.html'>Open latest benchmark-market card</a></div></div></section><!-- GOALOS_PROOF_ATLAS_V19_END -->"""

def proof_page(c, cards):
    lis=lambda xs: ''.join(f'<li>{esc(x)}</li>' for x in xs)
    metrics=''.join(f'<tr><td><strong>{esc(a)}</strong></td><td>{esc(b)}</td><td>{esc(d)}</td></tr>' for a,b,d in c['metrics'])
    contract_rows=''.join(f'<tr><td>{i+1}</td><td><code>{esc(x)}</code></td><td>{esc(contract_note(x))}</td></tr>' for i,x in enumerate(c['contracts']))
    agent_steps=''.join(f'<div class="step"><small>{i+1:02d}</small>{esc(a)}</div>' for i,a in enumerate(c['agents']))
    cards_links=''.join(f"<a href='proof-card-{x['id']}.html'><strong>{x['id']}</strong>{esc(x['title'])}</a>" for x in cards)
    body=f"""
<header class='pc-head'><div class='wrap'><div class='kicker'>Proof Card {esc(c['id'])} · {esc(c['domain'])}</div><h1>{esc(c['title'])}</h1><p class='lead'>{esc(c['short'])}</p><div class='badge-row'><span class='badge'>{esc(c['level'])}</span><span class='badge'>AGIALPHA coordinated</span><span class='badge'>Evidence Docket required</span><span class='badge'>RSI upgrade-gated</span></div><div class='buttons'><a class='btn' href='proof-cards.html'>All Proof Cards</a><a class='btn secondary' href='agialpha-ledger-route.html'>AGIALPHA Route</a><a class='btn secondary' href='sovereign-rsi-control-plane.html'>RSI Control Plane</a></div></div></header>
<div class='subnav'><div class='wrap'><a href='#mission'>Mission</a><a href='#agents'>Agent theater</a><a href='#agialpha'>AGIALPHA</a><a href='#contracts'>Contracts</a><a href='#evidence'>Evidence</a><a href='#rsi'>RSI</a><a href='#boundary'>Claim boundary</a></div></div>
<main><section id='mission' class='section'><div class='wrap'><div class='two'><div><div class='kicker'>Proof mission</div><h2>What this card proves architecturally</h2><p class='lead'>{esc(c['mission'])}</p><div class='note'><p><strong>Problem.</strong> {esc(c['problem'])}</p><p><strong>Why it matters.</strong> {esc(c['why'])}</p></div></div><div class='card hero-card'><h3>Incremental advance</h3><p>This card makes the portfolio stronger by adding a more demanding execution layer: sharper proof requirements, clearer specialist-agent roles, deeper AGIALPHA coordination, and stricter RSI propagation control.</p><p><strong>Current status:</strong> experimental proof-card template until live Evidence Docket is completed.</p></div></div></div></section>
<section id='agents' class='section'><div class='wrap'><div class='kicker'>Large specialist-agent operating theater</div><h2>Autonomous coordination to maximum effect</h2><p class='lead'>The system is not a loose swarm. It is a role-governed institution: each specialist cell has a bounded mandate, produces an artifact, and hands off to the next proof checkpoint.</p><div class='flow'>{agent_steps}</div></div></section>
<section class='section'><div class='wrap'><h2>Skills, plans, and goals used</h2><div class='three'><div class='card'><h3>Skills</h3><ul class='list'>{lis(c['skills'])}</ul></div><div class='card'><h3>Plans</h3><ul class='list'>{lis(c['plans'])}</ul></div><div class='card'><h3>Goals</h3><ul class='list'>{lis(c['goals'])}</ul></div></div></div></section>
<section id='agialpha' class='section'><div class='wrap'><div class='two'><div><h2>Where AGIALPHA becomes useful</h2><p class='lead'>{esc(c['agialpha'])}</p></div><div class='note'><h3>Plain-English ledger route</h3><p>AGIALPHA helps coordinate who sponsors, who claims work, who submits proof, who reviews, which artifacts become proof cards, which credentials are issued, and which work earns reputation.</p><p><strong>Token:</strong> {esc(TOKEN)}</p></div></div></div></section>
<section id='contracts' class='section'><div class='wrap'><h2>Smart-contract / registry route</h2><p>The proof path turns work into auditable institutional memory.</p><div class='mono'>{esc(route_text(c['contracts']))}</div><br><table class='table'><tr><th>#</th><th>Contract / registry</th><th>Contribution</th></tr>{contract_rows}</table></div></section>
<section id='evidence' class='section'><div class='wrap'><h2>Evidence Docket checklist</h2><div class='two'><div class='card'><ul class='list'>{lis(c['evidence'])}</ul></div><div class='card'><h3>Measured improvement logic</h3><table class='table'><tr><th>Dimension</th><th>Before</th><th>After proof-gated upgrade</th></tr>{metrics}</table></div></div></div></section>
<section id='rsi' class='section'><div class='wrap'><h2>RSI upgrade logic</h2><div class='note'><p>{esc(c['rsi'])}</p><p><strong>Operating principle:</strong> unproven work cannot become future operating context. Replayed, reviewed, selected, and rollback-ready work can.</p></div><div class='flow' style='margin-top:16px'><div class='step'>observe weakness</div><div class='step'>generate candidate</div><div class='step'>evaluate</div><div class='step'>prove</div><div class='step'>review</div><div class='step'>red-team</div><div class='step'>select</div><div class='step'>chronicle</div></div></div></section>
<section id='boundary' class='section'><div class='wrap'><h2>Claim boundary</h2><div class='card'><p>This page is an experimental public-safe proof-card template. It does not claim achieved AGI, achieved superintelligence, guaranteed financial return, legal/tax/security approval, offensive cyber capability, Ethereum mainnet deployment, or Kardashev Type II achievement. It defines the proof structure required before stronger claims can be made.</p></div></div></section>
<section class='section'><div class='wrap'><h2>Proof-card portfolio</h2><div class='atlas'>{cards_links}</div></div></section></main>"""
    return page(f"Proof Card {c['id']} - {c['title']}", body)

def integrate(site):
    cards=load_cards()
    site.mkdir(parents=True, exist_ok=True)
    index=site/'index.html'
    if not index.exists(): raise SystemExit('Existing main site did not build site/index.html; refusing destructive fallback.')
    txt=index.read_text(encoding='utf-8',errors='replace')
    block=home_block(cards)
    txt=re.sub(r'<!-- GOALOS_PROOF_.*?_START -->.*?<!-- GOALOS_PROOF_.*?_END -->', block, txt, flags=re.S)
    if 'GOALOS_PROOF_ATLAS_V19_START' not in txt:
        txt=txt.replace('</body>', block+'</body>') if '</body>' in txt else txt+block
    index.write_text(txt, encoding='utf-8')
    gallery=f"<main class='section'><div class='wrap'><div class='kicker'>Proof Card Command Center</div><h1>Substantial proof-card portfolio</h1><p class='lead'>Each card has a stable page with mission, multi-agent operating theater, AGIALPHA usage, contract route, skills, plans, goals, Evidence Docket, RSI logic, and claim boundary.</p>{card_grid(cards)}</div></main>"
    (site/'proof-cards.html').write_text(page('Proof Cards - GoalOS AGIALPHA Ascension', gallery), encoding='utf-8')
    for c in cards:
        (site/f'proof-card-{c["id"]}.html').write_text(proof_page(c,cards), encoding='utf-8')
    support = {
      'agialpha-ledger-route.html': ('Where AGIALPHA becomes useful', 'AGIALPHA coordinates proof-settled work: mission budgets, builder claim bonds, proof submissions, reviewer and red-team bonds, proof-card registration, credential issuance, reputation-linked routing, reward-vault settlement, treasury reinvestment, and Chronicle memory.'),
      'sovereign-rsi-control-plane.html': ('RSI as proof-backed upgrade rights', 'RSI means recursive self-improvement through evidence, evaluation, reviewer validation, challenge windows, rollback readiness, Selection Gate approval, and Chronicle memory.'),
      'evidence-docket.html': ('Evidence Docket', 'Every serious claim needs a docket: claim matrix, task manifest, baseline, run trace, artifact, evaluator report, reviewer attestation, red-team result, cost ledger, safety ledger, SelectionCertificate, rollback path, and delayed-outcome update.'),
      'season-001.html': ('Season 001', 'Season 001 should turn the proof-card portfolio into live Evidence Dockets, beginning with narrow, authorized, replayable missions.'),
      'share.html': ('Share kit', 'GoalOS turns AI work into auditable institutional capability. AGIALPHA coordinates proof-settled missions. RSI reuses only what proved itself.')
    }
    for fn,(title,content) in support.items():
        (site/fn).write_text(page(title, f"<main class='section'><div class='wrap'><h1>{esc(title)}</h1><p class='lead'>{esc(content)}</p><div class='mono'>{esc('GoalOSCommit -> RunCommitment -> Job -> Claim -> Proof -> Review -> ProofCard -> Credential -> Reputation -> EvidenceDocket -> SelectionGate -> Chronicle')}</div></div></main>"), encoding='utf-8')
    # Purge capitalized named-startup references from generated public pages.
    for p in site.rglob('*.html'):
        s=p.read_text(encoding='utf-8',errors='replace')
        s=s.replace('Recursive Self-Improvement','RSI')
        p.write_text(s, encoding='utf-8')
    print('Integrated Institutional Proof Atlas v19 into canonical main website root.')

def main():
    ap=argparse.ArgumentParser(); ap.add_argument('--site', default='site')
    args=ap.parse_args(); integrate(Path(args.site))
if __name__=='__main__': main()
